"use client";

import { useState, useEffect } from "react";
import { Search, FileDown, BookOpen } from "lucide-react";

export default function HomePage() {
  const [articles, setArticles] = useState([]);
  const [search, setSearch] = useState("");

  const fetchLatest = async () => {
    const res = await fetch("/api/articles"); // Nasze wcześniej stworzone API
    const data = await res.json();
    setArticles(data);
  };

  useEffect(() => { fetchLatest(); }, []);

  // Filtrowanie (Wymóg F7)
  const filteredArticles = articles.filter(art => 
    art.title.toLowerCase().includes(search.toLowerCase()) ||
    art.authors.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div className="min-h-screen bg-white">
      {/* HEADER (Wymóg NF3: Logo i ISSN stale widoczne) */}
      <header className="border-b bg-gray-50 p-6 shadow-sm">
        <div className="mx-auto max-w-6xl flex justify-between items-center">
          <div>
            <h1 className="text-3xl font-serif font-bold text-blue-900 uppercase tracking-tight">
              Scientia Nova
            </h1>
            <p className="text-sm font-mono text-gray-500">ISSN: 1234-5678-ABCD</p>
          </div>
          <nav className="flex gap-6 text-sm font-medium text-gray-600">
            <a href="#" className="hover:text-blue-600">O czasopiśmie</a>
            <a href="#" className="text-blue-600 border-b-2 border-blue-600">Najnowsze</a>
            <a href="#" className="hover:text-blue-600">Redakcja</a>
            <a href="/login" className="bg-gray-200 px-3 py-1 rounded hover:bg-gray-300">Admin</a>
          </nav>
        </div>
      </header>

      <main className="mx-auto max-w-5xl p-8">
        {/* Wyszukiwarka (F7) */}
        <div className="mb-12 relative">
          <Search className="absolute left-3 top-3 text-gray-400" size={20} />
          <input 
            type="text"
            placeholder="Szukaj artykułu po tytule lub autorze..."
            className="w-full border-2 border-gray-100 rounded-full py-3 pl-12 pr-4 focus:border-blue-300 outline-none transition"
            onChange={(e) => setSearch(e.target.value)}
          />
        </div>

        <h2 className="text-2xl font-bold mb-8 flex items-center gap-2">
          <BookOpen className="text-blue-600" /> Najnowsze Artykuły (2026)
        </h2>

        <div className="space-y-6">
          {filteredArticles.map((art: any) => (
            <div key={art.id} className="group border-l-4 border-blue-600 bg-gray-50 p-6 rounded-r-lg hover:shadow-md transition">
              <div className="flex justify-between items-start">
                <div className="flex-1">
                  <span className="text-xs font-bold uppercase text-blue-600 tracking-widest">
                    {art.category.name}
                  </span>
                  <h3 className="text-xl font-bold text-gray-900 mt-1 group-hover:text-blue-800 transition">
                    {art.title}
                  </h3>
                  <p className="text-gray-600 mt-2 font-medium">Autorzy: {art.authors}</p>
                  <div className="flex gap-4 mt-4 text-sm text-gray-400">
                    <span>Strony: {art.pageRange}</span>
                    <span>Data: {new Date(art.publicationDate).toLocaleDateString()}</span>
                  </div>
                </div>

                {/* PRZYCISK POBIERANIA (Triggeruje licznik statystyk - F4) */}
                <a 
                  href={`/api/download/${art.pdfPath}`} 
                  target="_blank"
                  className="flex flex-col items-center justify-center bg-white border-2 border-blue-600 text-blue-600 p-4 rounded-lg hover:bg-blue-600 hover:text-white transition"
                >
                  <FileDown size={28} />
                  <span className="text-[10px] font-bold mt-1">PDF</span>
                </a>
              </div>
            </div>
          ))}
          {filteredArticles.length === 0 && (
            <p className="text-center text-gray-400 py-10">Nie znaleziono artykułów spełniających kryteria.</p>
          )}
        </div>
      </main>
    </div>
  );
}